// Join NeurIPS Met test queries against the production embedding index.
// Outputs /tmp/met-bench/fullscale/join.json: qualifying queries, miss taxonomy,
// deterministic stratified sample of 500.
import fs from 'node:fs'
import { gunzipSync } from 'node:zlib'
import { createRequire } from 'node:module'
const Database = createRequire('/home/kuitang/git/met/package.json')('better-sqlite3')

const ROOT = '/home/kuitang/git/met'
const METDS = '/tmp/met-bench/metds'

const testset = JSON.parse(fs.readFileSync(`${METDS}/testset.json`, 'utf8'))
const queries = testset.filter((q) => q.path.startsWith('test_met/') && q.MET_id != null)
const idx = JSON.parse(fs.readFileSync(`${ROOT}/data/snapshots/image-embeddings/index.json`, 'utf8'))
const db = new Database(`${ROOT}/data/met.sqlite`, { readonly: true })
const getObj = db.prepare('SELECT objectID, galleryNumber, imageUrl FROM objects WHERE objectID = ?')

// snapshot for imageUrl presence (met.sqlite also has imageUrl per schema; use sqlite)
const qualifying = []
const excluded = []
for (const q of queries) {
  if (idx.objects[q.MET_id]) {
    qualifying.push({ MET_id: q.MET_id, path: q.path, gallery: idx.objects[q.MET_id].gallery, title: idx.objects[q.MET_id].title })
  } else {
    let row
    try { row = getObj.get(q.MET_id) } catch { row = undefined }
    let reason
    if (!row) reason = 'not-in-catalog (not on view today / no current gallery)'
    else if (!row.imageUrl) reason = 'on-view but no Open Access image'
    else reason = 'has image but missing from embedding index (pipeline gap)'
    excluded.push({ MET_id: q.MET_id, path: q.path, reason })
  }
}

const taxonomy = {}
for (const e of excluded) taxonomy[e.reason] = (taxonomy[e.reason] ?? 0) + 1

// Deterministic stratified sample of 500: sort by (gallery, path), stride-pick.
const sorted = [...qualifying].sort((a, b) => (a.gallery + a.path).localeCompare(b.gallery + b.path))
const N = 500
const sample = []
if (sorted.length <= 600) {
  sample.push(...sorted)
} else {
  const seen = new Set()
  for (let i = 0; i < N; i++) {
    const j = Math.floor((i * sorted.length) / N)
    if (!seen.has(j)) { seen.add(j); sample.push(sorted[j]) }
  }
}

const out = {
  totalTestMetQueries: queries.length,
  testMetFiles: fs.readdirSync(`${METDS}/test_met`).length,
  qualifying: qualifying.length,
  distinctGtObjects: new Set(qualifying.map((q) => q.MET_id)).size,
  excluded: excluded.length,
  taxonomy,
  sampleSize: sample.length,
  sampleGalleries: new Set(sample.map((q) => q.gallery)).size,
  sample,
  excludedRows: excluded,
}
fs.writeFileSync('/tmp/met-bench/fullscale/join.json', JSON.stringify(out, null, 1))
console.log(JSON.stringify({ ...out, sample: undefined, excludedRows: undefined }, null, 1))

provenance.embed.mjs:
// Embed the 500 sampled query photos with gemini-embedding-2, exactly the
// server's call shape (server/src/gemini.ts embedImage: inlineData image/jpeg,
// outputDimensionality 768, no taskType). Resumable: one JSON per query in
// /tmp/met-bench/qcache/. Polite: sequential + 150 ms gap, 30 s backoff on 429.
import fs from 'node:fs'
import path from 'node:path'
import { createRequire } from 'node:module'
const { GoogleGenAI } = createRequire('/home/kuitang/git/met/package.json')('@google/genai')

const METDS = '/tmp/met-bench/metds'
const CACHE = '/tmp/met-bench/qcache'
fs.mkdirSync(CACHE, { recursive: true })
const sleep = (ms) => new Promise((r) => setTimeout(r, ms))

const { sample } = JSON.parse(fs.readFileSync('/tmp/met-bench/fullscale/join.json', 'utf8'))
const ai = new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY })

let done = 0, fresh = 0
for (const q of sample) {
  const out = path.join(CACHE, path.basename(q.path).replace(/\.jpg$/, '.json'))
  if (fs.existsSync(out)) { done++; continue }
  const data = fs.readFileSync(path.join(METDS, q.path)).toString('base64')
  for (let a = 0; ; a++) {
    try {
      const response = await ai.models.embedContent({
        model: 'gemini-embedding-2',
        contents: [{ parts: [{ inlineData: { mimeType: 'image/jpeg', data } }] }],
        config: { outputDimensionality: 768 },
      })
      const values = response.embeddings?.[0]?.values
      if (!values || values.length !== 768) throw new Error('bad embedding')
      fs.writeFileSync(out, JSON.stringify(values))
      break
    } catch (e) {
      const msg = String(e).slice(0, 200)
      if (a >= 5) { console.error(`FAIL ${q.path}: ${msg}`); break }
      await sleep(/429|RESOURCE_EXHAUSTED/.test(msg) ? 30000 : 3000)
    }
  }
  done++; fresh++
  if (done % 25 === 0) console.log(`${done}/${sample.length} (${fresh} fresh)`)
  await sleep(150)
}
console.log(`done: ${done}/${sample.length}, fresh embeds: ${fresh}`)

provenance.score.mjs:
// Bulk scoring: brute-force cosine of each cached query embedding against the
// full 33,640-vector index (server semantics: pre-normalized rows, normalized
// query, dot = cosine). Object-level top-k dedupes the 3,017 stale duplicate
// rows (verified exact duplicates of mapped rows; the server's row-level top-3
// sees identical similarities). Outputs results.json with per-query rows.
import fs from 'node:fs'
import path from 'node:path'

const ROOT = '/home/kuitang/git/met'
const D = `${ROOT}/data/snapshots/image-embeddings`
const CACHE = '/tmp/met-bench/qcache'

const idx = JSON.parse(fs.readFileSync(`${D}/index.json`, 'utf8'))
const { dims, shardSize, count } = idx
const matrix = new Float32Array(count * dims)
for (let s = 0; s * shardSize < count; s++) {
  const buf = fs.readFileSync(`${D}/shard-${s}.bin`)
  matrix.set(
    new Float32Array(buf.buffer, buf.byteOffset, buf.byteLength / 4).subarray(0, Math.min(buf.byteLength / 4, (count - s * shardSize) * dims)),
    s * shardSize * dims,
  )
}
const rowMeta = new Array(count) // {objectID, gallery} or undefined (stale dup row)
for (const [id, o] of Object.entries(idx.objects))
  rowMeta[o.shard * shardSize + o.offset] = { objectID: Number(id), gallery: o.gallery, title: o.title }

const { sample } = JSON.parse(fs.readFileSync('/tmp/met-bench/fullscale/join.json', 'utf8'))
const rows = []
for (const q of sample) {
  const f = path.join(CACHE, path.basename(q.path).replace(/\.jpg$/, '.json'))
  if (!fs.existsSync(f)) { rows.push({ ...q, error: 'no-embedding' }); continue }
  const vec = Float32Array.from(JSON.parse(fs.readFileSync(f, 'utf8')))
  let n = 0
  for (let i = 0; i < dims; i++) n += vec[i] * vec[i]
  n = Math.sqrt(n) || 1
  // best similarity per objectID (stale rows fold into their mapped twin)
  const best = new Map()
  let gtSim = -2
  for (let r = 0; r < count; r++) {
    let dot = 0
    const base = r * dims
    for (let i = 0; i < dims; i++) dot += matrix[base + i] * vec[i]
    const sim = dot / n
    const meta = rowMeta[r]
    if (!meta) continue
    const prev = best.get(meta.objectID)
    if (prev === undefined || sim > prev) best.set(meta.objectID, sim)
    if (meta.objectID === q.MET_id && sim > gtSim) gtSim = sim
  }
  const sorted = [...best.entries()].sort((a, b) => b[1] - a[1]).slice(0, 5)
  const topIds = sorted.map(([id]) => id)
  const top1Meta = idx.objects[topIds[0]]
  const bestWrong = sorted.find(([id]) => id !== q.MET_id)
  rows.push({
    ...q,
    top5: sorted.map(([id, sim]) => ({ id, sim: Number(sim.toFixed(4)), gallery: idx.objects[id].gallery })),
    top1: topIds[0] === q.MET_id,
    top5hit: topIds.includes(q.MET_id),
    galleryHit: top1Meta.gallery === q.gallery,
    gtSim: Number(gtSim.toFixed(4)),
    bestWrongSim: bestWrong ? Number(bestWrong[1].toFixed(4)) : null,
  })
  if (rows.length % 50 === 0) console.log(rows.length)
}

const ok = rows.filter((r) => !r.error)
const pct = (n, d) => `${((100 * n) / d).toFixed(1)}% (${n}/${d})`
const med = (a, q = 0.5) => { const s = [...a].sort((x, y) => x - y); return s[Math.min(s.length - 1, Math.floor(s.length * q))] }
const top1 = ok.filter((r) => r.top1).length
const top5 = ok.filter((r) => r.top5hit).length
const gal = ok.filter((r) => r.galleryHit).length
const hits = ok.filter((r) => r.top1)
const misses = ok.filter((r) => !r.top1)
const summary = {
  queries: ok.length,
  top1: pct(top1, ok.length),
  top5: pct(top5, ok.length),
  gallery: pct(gal, ok.length),
  hitMarginMedian: med(hits.map((r) => r.gtSim - r.bestWrongSim)),
  hitGtSimMedian: med(hits.map((r) => r.gtSim)),
  missGtSimMedian: med(misses.map((r) => r.gtSim)),
  missTop1SimMedian: med(misses.map((r) => r.top5[0].sim)),
  missDeficitMedian: med(misses.map((r) => r.top5[0].sim - r.gtSim)),
}
console.log(JSON.stringify(summary, null, 1))
fs.writeFileSync('/tmp/met-bench/fullscale/results.json', JSON.stringify({ summary, rows }, null, 1))

provenance.live.mjs:
// Live pass: 40 stratified photos from the bulk sample through the real
// POST /api/v1/locate/photo (prod server, real Gemini, no mock).
import fs from 'node:fs'
import path from 'node:path'

const SERVER = process.env.SERVER ?? 'http://localhost:8788'
const METDS = '/tmp/met-bench/metds'
const { sample } = JSON.parse(fs.readFileSync('/tmp/met-bench/fullscale/join.json', 'utf8'))

// deterministic stratified 40: sample is gallery-sorted; take every Nth
const picks = []
const seen = new Set()
for (let i = 0; i < 40; i++) {
  const j = Math.floor((i * sample.length) / 40)
  if (!seen.has(j)) { seen.add(j); picks.push(sample[j]) }
}

const rows = []
for (const q of picks) {
  const img = fs.readFileSync(path.join(METDS, q.path)).toString('base64')
  const t0 = Date.now()
  const row = { MET_id: q.MET_id, path: q.path, gallery: q.gallery }
  try {
    const r = await fetch(`${SERVER}/api/v1/locate/photo`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ imageBase64: img }),
    })
    row.ms = Date.now() - t0
    row.status = r.status
    const j = await r.json()
    if (!r.ok) row.error = JSON.stringify(j).slice(0, 200)
    else {
      row.label = j.label
      row.candidates = j.candidates.map((c) => ({ id: c.objectID, gallery: c.gallery, sim: c.similarity }))
      const ids = j.candidates.map((c) => c.objectID)
      row.top1 = ids[0] === q.MET_id
      row.top3 = ids.includes(q.MET_id)
      row.galleryHit = j.candidates[0]?.gallery === q.gallery
    }
  } catch (e) {
    row.error = String(e).slice(0, 200)
  }
  rows.push(row)
  console.log(`${rows.length}/${picks.length} ${q.MET_id} ${row.ms}ms top1=${row.top1} top3=${row.top3} label=${JSON.stringify(row.label ?? null)?.slice(0, 60)}`)
  await new Promise((r) => setTimeout(r, 300))
}

const ok = rows.filter((r) => !r.error)
const med = (a, q = 0.5) => { const s = [...a].sort((x, y) => x - y); return s[Math.min(s.length - 1, Math.floor(s.length * q))] }
const summary = {
  requested: picks.length,
  ok: ok.length,
  errors: rows.length - ok.length,
  p50: med(ok.map((r) => r.ms)),
  p95: med(ok.map((r) => r.ms), 0.95),
  top1: ok.filter((r) => r.top1).length,
  top3: ok.filter((r) => r.top3).length,
  galleryHit: ok.filter((r) => r.galleryHit).length,
  labelNull: ok.filter((r) => r.label === null).length,
  labelNonNull: ok.filter((r) => r.label !== null).length,
}
console.log(JSON.stringify(summary, null, 1))
fs.writeFileSync('/tmp/met-bench/fullscale/live-results.json', JSON.stringify({ summary, rows }, null, 1))
